var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"할 게 생각보다 많네.","JPN":"意外とやることが多いわね。","ENG":"There's a lot more work to do than I expected.","TWN":"沒想到有那麼多要預備的。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"라우라, 그쪽은 어때?","JPN":"ラウラ、そっちはどう？","ENG":"Laura, how are you doing?","TWN":"蘿拉，你那邊怎麼樣？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"바쁜 거 안 보여? 일손 부족하면 유나나 잉그리드 시켜.","JPN":"こっちも忙しい。人手が足りないならユナかイングリッドに頼め。","ENG":"Can't you see I'm busy? Make Yuna or Ingrid do it if you need an extra hand.","TWN":"沒看到我很忙嗎？人手不夠就使喚尤娜和英格麗。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"우리도 바빴거든? 웨딩 드레스를 몇 벌이나 만들었는데!","JPN":"私たちも忙しかったんだよ！　ウェディングドレスを何着作ったと思う？","ENG":"We were busy too, you know. Do you know how many wedding dresses we made?!","TWN":"我們也很忙好嗎！我們已經做好幾件婚紗咧！"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"그래! 옷 만드는 게 어디 쉬운 일인 줄 알아?","JPN":"そうだよ！　ドレスを作るのって簡単じゃないんだよ！","ENG":"Yeah! Do you think making dresses is a piece of cake?","TWN":"就是說！你以為做衣服很容易嗎？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"하아? 이제 옷 좀 만들어 봤다, 이거야?","JPN":"はあ？　何着かドレスを作ったくらいで偉そうに。","ENG":"Oh, so now you think you know your clothes, huh?","TWN":"蛤？才做幾件衣服就囂張啦？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그만큼 잘 만들었던데? 다들 고생 많았어.","JPN":"それくらいよくできていたわよ？　頑張ったわね。","ENG":"To be fair, they did a good job. Great work, everyone.","TWN":"做得很好呢？你們辛苦囉。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"거 봐!","JPN":"ほら！","ENG":"See?","TWN":"看吧！"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"…뭐. 급하게 만든 작업물치고 나쁘진 않았다만.","JPN":"……まあ、急いで作った割にはよくできていたが。","ENG":"...Fine. It wasn't terrible, considering the small amount of time they had.","TWN":"……嗯哼，在短時間內做出這樣的成品，確實還不錯啦。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"자세히 뜯어보면 또 모르지. 바느질이 엉망이라 금방 뜯어질 수도 있는 거고.","JPN":"でも、細かく見ないとわからない！　縫い方が雑だからすぐに破れてしまうかもしれないしな。","ENG":"BUT! Maybe upon closer inspection, the stitching is a mess and it falls apart. You never know.","TWN":"不過細看的話就不一定囉，線縫得亂七八糟的，好像一下就會裂開的樣子。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"우으, 정말 심술 궂다니깐.","JPN":"うう、本当に意地悪なんだから。","ENG":"Ugh, you're so mean.","TWN":"嗚嗚，蘿拉嘴巴好壞。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"창고에서 드레스랑 어울릴 만한 것 좀 찾아 올게!","JPN":"倉庫からドレスに似合うようなもの探してくるね！","ENG":"I'm gonna go to the storage room and find some extra things to pair with the dress!","TWN":"我去倉庫找找有沒有適合搭配婚紗的東西。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"나도 같이 가!","JPN":"私も行くよ！","ENG":"Wait for me!","TWN":"我也一起去！"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"……좀 불안한데. 또 이상한 거 주워 오는 거 아냐?","JPN":"……不安だな。また変なものを拾ってくるんじゃないのか？","ENG":"...Something feels wrong. What if they bring some weird garbage?","TWN":"……我有點不好的預感，她們該不會又撿什麼奇怪的東西回來吧？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"밖은 또 왜 이렇게 시끄러워?","JPN":"外はなんでまた騒がしいんだ？","ENG":"And why is it so noisy outside?","TWN":"外面怎麼這麼吵？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"아직 오픈 전인데. 벌써 신 메뉴 소식을 들은 건가?","JPN":"まだ、オープン前なのにね。もう新メニューの噂を聞きつけたのかしら？","ENG":"We haven't opened yet. Or did they already hear about our new menu?","TWN":"都還沒開門客人就已經收到消息，知道我們要推出新菜單嗎？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};